"use strict";parserFactory.register("sj.uukanshu.com",()=>new SjuukanshuParser);class SjuukanshuParser extends Parser{constructor(){super()}async getChapterUrls(e){let r=e.querySelector("#listCont .ml-list");return util.hyperlinksToChapterList(r)}findContent(e){return e.querySelector("#bookContent")}extractTitleImpl(e){return e.querySelector("h1.bookname")}findChapterTitle(e){return e.querySelector("h3")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".book-info")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.desc")]}}